prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?defs ?choreo WHERE {
  ?model a bboExt:Model .
  FILTER(?model = <https://www.teamingai-project.eu/model/0ba102e82f484407a4dbcb9bcafdd920> || 
         ?model = <http://www.onto-bpo.eu/ontologies/bboExtension#0ba102e82f484407a4dbcb9bcafdd920>)
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?defs tai:belongsTo ?model . }
  OPTIONAL { ?choreo tai:belongsTo ?defs . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(CONTAINS(STR(?model), "0ba102e82f484407a4dbcb9bcafdd920") ||
         CONTAINS(STR(?normId), "0ba102e82f484407a4dbcb9bcafdd920") ||
         CONTAINS(STR(?origId), "0ba102e82f484407a4dbcb9bcafdd920"))
}
LIMIT 25
